     5→type CardCarouselProps = {
     6→  /**
     7→   * Whether the carousel loops continuously.
     8→   * @default true
     9→   */
    10→  loop?: boolean;
    11→
    12→  /**
    13→   * Whether the carousel advances slides automatically.
    14→   * When true, pauses on hover and touch interaction.
    15→   * @default false
    16→   */
    17→  autoPlay?: boolean;
    18→
    19→  /**
    20→   * Card-like elements to display in the carousel.
    21→   * Each React element in the flattened children array becomes one slide.
    22→   * Fragments are transparent — they unwrap into individual slides, not a single grouped slide.
    23→   */
    24→  children: React.ReactNode;
    25→} & Omit<React.ComponentPropsWithoutRef<'div'>, 'children'>;
