    27→const AUTOPLAY_INTERVAL = 5000;
    28→
    29→/**
    30→ * keen-slider v6 only listens to window.resize for recalculation. It does NOT
    31→ * observe its own container. If the container settles to a different size after
    32→ * mount (Storybook docs layout, tabs, accordion panels, sidebar toggles),
    33→ * keen-slider keeps the stale measurement — causing wrong slide widths and
    34→ * loop-clone overlap. This plugin bridges that gap.
    35→ */
    36→const containerResizePlugin: KeenSliderPlugin = (slider) => {
    37→  const observer = new ResizeObserver(() => slider.update());
    38→  slider.on('created', () => observer.observe(slider.container));
    39→  slider.on('destroyed', () => observer.disconnect());
    40→};
    41→
    42→const autoPlayPlugin: KeenSliderPlugin = (slider) => {
    43→  let timeout: ReturnType<typeof setTimeout>;
    44→  let paused = false;
    45→
    46→  function clearTimer() {
    47→    clearTimeout(timeout);
    48→  }
    49→
    50→  function startTimer() {
    51→    clearTimer();
    52→    if (!paused) {
    53→      timeout = setTimeout(() => {
    54→        slider.next();
    55→      }, AUTOPLAY_INTERVAL);
    56→    }
    57→  }
    58→
    59→  function pause() {
    60→    paused = true;
    61→    clearTimer();
    62→  }
    63→
    64→  function resume() {
    65→    paused = false;
    66→    startTimer();
    67→  }
    68→
    69→  slider.on('created', startTimer);
    70→  slider.on('animationEnded', startTimer);
    71→  slider.on('dragStarted', pause);
    72→  slider.on('dragEnded', resume);
    73→
    74→  const container = slider.container;
    75→  container.addEventListener('mouseenter', pause);
    76→  container.addEventListener('mouseleave', resume);
    77→  container.addEventListener('touchstart', pause, { passive: true });
    78→  container.addEventListener('touchend', resume);
    79→
    80→  slider.on('destroyed', () => {
    81→    clearTimer();
    82→    container.removeEventListener('mouseenter', pause);
    83→    container.removeEventListener('mouseleave', resume);
    84→    container.removeEventListener('touchstart', pause);
    85→    container.removeEventListener('touchend', resume);
    86→  });
    87→};
